+                sandbox.platform_name()
+            );
+            return;
+        }
+
+        // If available, we still avoid applying in tests on non-Linux to prevent
+        // platform-specific side effects. This keeps the skip explicit.
+        eprintln!(
+            "skipping sandbox apply integration on {} in tests",
+            sandbox.platform_name()
+        );
+    }
+}
